    vec3 dy = ( GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv-vec2(0,1)*d) );

vec2 uv_red = 0.5 + (vUv-0.5)*0.996 - vec2(0,1)*uTexSize.zw - vec2(lum(dx),lum(dy))*uTexSize.zw*4;

uv_red = fract(uv_red); // fix for the old Radeons
    ret = texture( sampler_main, uv_red ).xyz;

